#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int A[N];
        for(int i=0;i<N;i++) scanf("%d",&A[i]);
        int B;
        int cur=0, best=0;
        for(int i=0;i<N;i++){
            scanf("%d",&B);
            if(A[i]>0 && B>0){
                cur++;
                if(cur>best) best=cur;
            }else{
                cur=0;
            }
        }
        printf("%d\n",best);
    }
    return 0;
}

