using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int>A(N);
        for(int &x:A) cin>>x;
        int cur=0,best=0;
        for(int i=0;i<N;i++){
            int b; cin>>b;
            if(A[i]>0 && b>0){
                ++cur;
                best=max(best,cur);
            }else cur=0;
        }
        cout<<best<<"\n";
    }
    return 0;
}

