import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        cur = best = 0
        for i in range(N):
            b = int(next(it))
            if A[i] > 0 and b > 0:
                cur += 1
                if cur > best:
                    best = cur
            else:
                cur = 0
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

